const html = "<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>University Data Quality</title>
  <style>
    :root {
      --bg: #f5f7f6;
      --surface: #ffffff;
      --surface-2: #f9faf8;
      --text: #1d2520;
      --muted: #65736b;
      --line: #d7ddd9;
      --line-strong: #b9c4be;
      --green: #2f7d54;
      --green-soft: #e4f3ea;
      --amber: #a86f13;
      --amber-soft: #fff1d6;
      --red: #b63f3a;
      --red-soft: #fbe7e5;
      --teal: #1f766f;
      --teal-soft: #dff3f1;
      --violet: #6656a5;
      --violet-soft: #ece9f7;
      --charcoal: #2d3330;
      --shadow: 0 10px 28px rgba(32, 42, 36, 0.08);
      --radius: 8px;
      --font: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    }

    * { box-sizing: border-box; }
    html, body { height: 100%; }
    body {
      margin: 0;
      background: var(--bg);
      color: var(--text);
      font-family: var(--font);
      font-size: 14px;
      letter-spacing: 0;
    }

    button, input, select, textarea {
      font: inherit;
      letter-spacing: 0;
    }

    button {
      border: 1px solid var(--line-strong);
      background: var(--surface);
      color: var(--text);
      min-height: 36px;
      padding: 0 12px;
      border-radius: 6px;
      cursor: pointer;
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 8px;
      white-space: nowrap;
    }

    button:hover { border-color: var(--charcoal); }
    button.primary {
      border-color: var(--green);
      background: var(--green);
      color: #fff;
    }
    button.danger {
      border-color: var(--red);
      color: var(--red);
    }
    button:disabled {
      opacity: 0.55;
      cursor: not-allowed;
    }

    input, select, textarea {
      width: 100%;
      min-height: 36px;
      border: 1px solid var(--line);
      border-radius: 6px;
      background: #fff;
      color: var(--text);
      padding: 8px 10px;
      outline: none;
    }
    textarea { min-height: 92px; resize: vertical; }
    input:focus, select:focus, textarea:focus { border-color: var(--teal); box-shadow: 0 0 0 3px rgba(31, 118, 111, 0.12); }

    .app-shell {
      min-height: 100%;
      display: grid;
      grid-template-rows: auto auto 1fr;
    }

    .topbar {
      height: 64px;
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 0 24px;
      background: var(--surface);
      border-bottom: 1px solid var(--line);
      position: sticky;
      top: 0;
      z-index: 20;
    }
    .brand {
      display: flex;
      align-items: center;
      gap: 12px;
      min-width: 0;
    }
    .brand-mark {
      width: 34px;
      height: 34px;
      border-radius: 7px;
      background: var(--charcoal);
      color: #fff;
      display: grid;
      place-items: center;
      font-weight: 800;
    }
    .brand h1 {
      font-size: 17px;
      margin: 0;
      line-height: 1.1;
    }
    .brand span {
      color: var(--muted);
      font-size: 12px;
    }
    .top-actions { display: flex; gap: 8px; align-items: center; }

    .tabs {
      display: flex;
      gap: 6px;
      padding: 12px 24px 0;
      overflow-x: auto;
      background: var(--bg);
    }
    .tab {
      min-height: 38px;
      border-color: transparent;
      background: transparent;
      color: var(--muted);
      border-bottom: 2px solid transparent;
      border-radius: 6px 6px 0 0;
    }
    .tab.active {
      color: var(--text);
      background: var(--surface);
      border-color: var(--line);
      border-bottom-color: var(--surface);
    }

    main {
      padding: 16px 24px 28px;
      display: grid;
      gap: 16px;
    }

    .panel {
      background: var(--surface);
      border: 1px solid var(--line);
      border-radius: var(--radius);
      box-shadow: var(--shadow);
    }
    .panel-header {
      min-height: 48px;
      padding: 12px 14px;
      border-bottom: 1px solid var(--line);
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 12px;
    }
    .panel-title {
      display: flex;
      align-items: baseline;
      gap: 8px;
      min-width: 0;
    }
    .panel-title h2 {
      margin: 0;
      font-size: 14px;
      font-weight: 750;
    }
    .panel-title span {
      color: var(--muted);
      font-size: 12px;
    }
    .panel-body { padding: 14px; }

    .kpi-grid {
      display: grid;
      grid-template-columns: repeat(8, minmax(132px, 1fr));
      gap: 10px;
    }
    .kpi {
      background: var(--surface);
      border: 1px solid var(--line);
      border-radius: var(--radius);
      padding: 12px;
      min-height: 92px;
      display: grid;
      align-content: space-between;
    }
    .kpi label {
      color: var(--muted);
      font-size: 12px;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }
    .kpi strong {
      font-size: 26px;
      line-height: 1;
      margin-top: 8px;
    }
    .kpi small {
      color: var(--muted);
      margin-top: 8px;
      display: block;
      min-height: 16px;
    }

    .grid-2 { display: grid; grid-template-columns: minmax(0, 1fr) minmax(0, 1fr); gap: 16px; }
    .grid-3 { display: grid; grid-template-columns: 1.1fr 1fr 1fr; gap: 16px; }
    .grid-main { display: grid; grid-template-columns: 280px minmax(0, 1fr); gap: 16px; align-items: start; }

    .filters {
      display: grid;
      gap: 10px;
      position: sticky;
      top: 128px;
    }
    .filter-row { display: grid; gap: 6px; }
    .filter-row label {
      color: var(--muted);
      font-size: 12px;
      font-weight: 650;
    }

    .toolbar {
      display: flex;
      flex-wrap: wrap;
      gap: 8px;
      align-items: center;
    }
    .toolbar select { width: auto; min-width: 160px; }

    .chart-box {
      min-height: 250px;
      display: grid;
      grid-template-rows: auto 1fr;
      gap: 8px;
    }
    canvas {
      width: 100%;
      min-height: 206px;
      display: block;
    }
    .legend {
      display: flex;
      flex-wrap: wrap;
      gap: 8px 12px;
      color: var(--muted);
      font-size: 12px;
    }
    .legend-item { display: inline-flex; align-items: center; gap: 6px; }
    .dot {
      width: 9px;
      height: 9px;
      border-radius: 999px;
      background: var(--muted);
      flex: 0 0 auto;
    }

    .bar-list { display: grid; gap: 9px; }
    .bar-row {
      display: grid;
      grid-template-columns: 132px 1fr 44px;
      gap: 10px;
      align-items: center;
      font-size: 12px;
      color: var(--muted);
    }
    .bar-track {
      height: 11px;
      background: #eef1ef;
      border-radius: 999px;
      overflow: hidden;
    }
    .bar-fill {
      height: 100%;
      border-radius: 999px;
      background: var(--teal);
    }

    .heatmap {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(170px, 1fr));
      gap: 8px;
    }
    .heat-cell {
      border: 1px solid var(--line);
      border-radius: 6px;
      padding: 10px;
      display: grid;
      gap: 7px;
      background: var(--surface-2);
      min-width: 0;
    }
    .heat-cell strong {
      font-size: 12px;
      overflow-wrap: anywhere;
    }
    .heat-cell span { color: var(--muted); font-size: 12px; }
    .heat-rail {
      height: 6px;
      background: #e9eeeb;
      border-radius: 999px;
      overflow: hidden;
    }
    .heat-rail i { display: block; height: 100%; border-radius: 999px; }

    .table-wrap {
      overflow: auto;
      border: 1px solid var(--line);
      border-radius: var(--radius);
      background: var(--surface);
    }
    table {
      width: 100%;
      border-collapse: collapse;
      min-width: 1120px;
    }
    th, td {
      padding: 10px 11px;
      border-bottom: 1px solid var(--line);
      text-align: left;
      vertical-align: middle;
      white-space: nowrap;
    }
    th {
      color: var(--muted);
      font-size: 12px;
      font-weight: 750;
      background: var(--surface-2);
      position: sticky;
      top: 0;
      z-index: 1;
    }
    td.name-cell {
      min-width: 280px;
      white-space: normal;
      line-height: 1.35;
    }
    .muted { color: var(--muted); }
    .mono {
      font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, "Liberation Mono", monospace;
      font-size: 12px;
    }

    .pill {
      display: inline-flex;
      align-items: center;
      min-height: 24px;
      padding: 0 9px;
      border-radius: 999px;
      font-size: 12px;
      font-weight: 700;
      border: 1px solid transparent;
      white-space: nowrap;
    }
    .pill.verified { background: var(--green-soft); color: var(--green); border-color: #b8dcc6; }
    .pill.probable { background: var(--teal-soft); color: var(--teal); border-color: #a9d9d4; }
    .pill.review { background: var(--amber-soft); color: var(--amber); border-color: #f0cf91; }
    .pill.risky { background: var(--red-soft); color: var(--red); border-color: #edbab6; }
    .pill.neutral { background: #eef1ef; color: var(--muted); border-color: var(--line); }

    .score {
      width: 56px;
      font-weight: 800;
      text-align: right;
    }

    .issue-list {
      display: grid;
      gap: 8px;
      max-height: 360px;
      overflow: auto;
    }
    .issue {
      border: 1px solid var(--line);
      border-left-width: 4px;
      border-radius: 6px;
      padding: 9px 10px;
      display: grid;
      gap: 4px;
      background: var(--surface-2);
    }
    .issue.critical { border-left-color: var(--red); }
    .issue.major { border-left-color: var(--amber); }
    .issue.minor { border-left-color: var(--teal); }
    .issue strong { font-size: 12px; overflow-wrap: anywhere; }
    .issue span { color: var(--muted); font-size: 12px; overflow-wrap: anywhere; }

    .export-box {
      display: grid;
      grid-template-columns: repeat(3, minmax(0, 1fr));
      gap: 12px;
    }
    .metric {
      border: 1px solid var(--line);
      border-radius: 6px;
      padding: 12px;
      background: var(--surface-2);
    }
    .metric label { color: var(--muted); font-size: 12px; display: block; }
    .metric strong { display: block; margin-top: 6px; font-size: 22px; }

    .drawer-backdrop {
      position: fixed;
      inset: 0;
      background: rgba(20, 27, 23, 0.34);
      display: none;
      z-index: 40;
    }
    .drawer-backdrop.open { display: block; }
    .drawer {
      position: fixed;
      top: 0;
      right: 0;
      height: 100%;
      width: min(860px, 100%);
      background: var(--surface);
      border-left: 1px solid var(--line);
      transform: translateX(100%);
      transition: transform 180ms ease;
      z-index: 50;
      display: grid;
      grid-template-rows: auto 1fr auto;
      box-shadow: -18px 0 34px rgba(32, 42, 36, 0.16);
    }
    .drawer.open { transform: translateX(0); }
    .drawer-header,
    .drawer-footer {
      padding: 14px 16px;
      border-bottom: 1px solid var(--line);
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 12px;
    }
    .drawer-footer { border-bottom: 0; border-top: 1px solid var(--line); }
    .drawer-title { min-width: 0; }
    .drawer-title h3 {
      margin: 0 0 4px;
      font-size: 16px;
      line-height: 1.2;
      overflow-wrap: anywhere;
    }
    .drawer-body {
      overflow: auto;
      padding: 16px;
      display: grid;
      gap: 16px;
    }
    .form-grid {
      display: grid;
      grid-template-columns: repeat(2, minmax(0, 1fr));
      gap: 12px;
    }
    .form-field {
      display: grid;
      gap: 6px;
      min-width: 0;
    }
    .form-field.full { grid-column: 1 / -1; }
    .form-field label {
      color: var(--muted);
      font-size: 12px;
      font-weight: 700;
      overflow-wrap: anywhere;
    }
    .evidence-list {
      display: grid;
      gap: 7px;
    }
    .evidence-list a {
      color: var(--teal);
      text-decoration: none;
      overflow-wrap: anywhere;
    }
    .evidence-list a:hover { text-decoration: underline; }

    .empty {
      min-height: 180px;
      display: grid;
      place-items: center;
      color: var(--muted);
      border: 1px dashed var(--line-strong);
      border-radius: var(--radius);
      background: var(--surface-2);
      text-align: center;
      padding: 20px;
    }

    .toast {
      position: fixed;
      left: 50%;
      bottom: 24px;
      transform: translateX(-50%);
      background: var(--charcoal);
      color: #fff;
      padding: 10px 14px;
      border-radius: 6px;
      box-shadow: var(--shadow);
      display: none;
      z-index: 80;
      max-width: min(520px, calc(100% - 32px));
    }
    .toast.open { display: block; }

    [hidden] { display: none !important; }

    @media (max-width: 1280px) {
      .kpi-grid { grid-template-columns: repeat(4, minmax(132px, 1fr)); }
      .grid-3 { grid-template-columns: 1fr; }
      .grid-2 { grid-template-columns: 1fr; }
    }

    @media (max-width: 860px) {
      .topbar { height: auto; min-height: 64px; padding: 12px 14px; align-items: flex-start; gap: 12px; }
      .top-actions { flex-wrap: wrap; justify-content: flex-end; }
      .tabs { padding-left: 14px; padding-right: 14px; }
      main { padding: 14px; }
      .kpi-grid { grid-template-columns: repeat(2, minmax(0, 1fr)); }
      .grid-main { grid-template-columns: 1fr; }
      .filters { position: static; }
      .export-box { grid-template-columns: 1fr; }
      .form-grid { grid-template-columns: 1fr; }
      .brand span { display: none; }
    }

    @media (max-width: 520px) {
      .kpi-grid { grid-template-columns: 1fr; }
      .bar-row { grid-template-columns: 96px 1fr 38px; }
      .topbar { flex-direction: column; }
      .top-actions { justify-content: flex-start; }
    }
  </style>
</head>
<body>
  <div class="app-shell">
    <header class="topbar">
      <div class="brand">
        <div class="brand-mark">UQ</div>
        <div>
          <h1>University Data Quality</h1>
          <span id="runMeta">n8n dashboard</span>
        </div>
      </div>
      <div class="top-actions">
        <button id="refreshBtn" type="button">Refresh</button>
        <button id="exportBtn" class="primary" type="button">Download CSV</button>
      </div>
    </header>

    <nav class="tabs" aria-label="Dashboard views">
      <button class="tab active" type="button" data-tab="overview">Overview</button>
      <button class="tab" type="button" data-tab="quality">Data Quality</button>
      <button class="tab" type="button" data-tab="trust">Trust & Evidence</button>
      <button class="tab" type="button" data-tab="review">Review Queue</button>
      <button class="tab" type="button" data-tab="export">Export Center</button>
    </nav>

    <main>
      <section class="kpi-grid" id="kpis"></section>

      <section data-view="overview">
        <div class="grid-3">
          <article class="panel chart-box">
            <div class="panel-header">
              <div class="panel-title"><h2>Status Distribution</h2><span id="statusTotal"></span></div>
            </div>
            <div class="panel-body">
              <canvas id="statusChart" height="220"></canvas>
              <div class="legend" id="statusLegend"></div>
            </div>
          </article>
          <article class="panel chart-box">
            <div class="panel-header">
              <div class="panel-title"><h2>Score Bands</h2></div>
            </div>
            <div class="panel-body">
              <div class="bar-list" id="scoreBands"></div>
            </div>
          </article>
          <article class="panel chart-box">
            <div class="panel-header">
              <div class="panel-title"><h2>Source Mix</h2></div>
            </div>
            <div class="panel-body">
              <canvas id="sourceChart" height="220"></canvas>
              <div class="legend" id="sourceLegend"></div>
            </div>
          </article>
        </div>
      </section>

      <section data-view="quality" hidden>
        <div class="grid-2">
          <article class="panel">
            <div class="panel-header">
              <div class="panel-title"><h2>Field Completeness</h2><span id="fieldCompletenessMeta"></span></div>
            </div>
            <div class="panel-body">
              <div class="heatmap" id="heatmap"></div>
            </div>
          </article>
          <article class="panel">
            <div class="panel-header">
              <div class="panel-title"><h2>Schema & Outliers</h2></div>
            </div>
            <div class="panel-body">
              <div class="bar-list" id="outliers"></div>
              <div class="issue-list" id="schemaIssues" style="margin-top: 14px;"></div>
            </div>
          </article>
        </div>
      </section>

      <section data-view="trust" hidden>
        <div class="grid-2">
          <article class="panel">
            <div class="panel-header">
              <div class="panel-title"><h2>Evidence Confidence</h2></div>
            </div>
            <div class="panel-body">
              <canvas id="trustChart" height="260"></canvas>
              <div class="legend" id="trustLegend"></div>
            </div>
          </article>
          <article class="panel">
            <div class="panel-header">
              <div class="panel-title"><h2>Risk Flags</h2></div>
            </div>
            <div class="panel-body">
              <div class="issue-list" id="riskFlags"></div>
            </div>
          </article>
        </div>
      </section>

      <section class="grid-main" data-view="review" hidden>
        <aside class="panel filters">
          <div class="panel-header"><div class="panel-title"><h2>Filters</h2></div></div>
          <div class="panel-body" style="display: grid; gap: 10px;">
            <div class="filter-row">
              <label for="searchInput">Search</label>
              <input id="searchInput" type="search" placeholder="Name, slug, website">
            </div>
            <div class="filter-row">
              <label for="countryFilter">Country code</label>
              <select id="countryFilter"></select>
            </div>
            <div class="filter-row">
              <label for="statusFilter">Quality status</label>
              <select id="statusFilter">
                <option value="">All</option>
                <option>Verified</option>
                <option>Probable</option>
                <option>Needs Review</option>
                <option>Risky</option>
              </select>
            </div>
            <div class="filter-row">
              <label for="scoreFilter">Score band</label>
              <select id="scoreFilter">
                <option value="">All</option>
                <option value="85-100">85-100</option>
                <option value="70-84">70-84</option>
                <option value="45-69">45-69</option>
                <option value="0-44">0-44</option>
              </select>
            </div>
            <div class="filter-row">
              <label for="missingFilter">Missing field</label>
              <select id="missingFilter"></select>
            </div>
            <div class="filter-row">
              <label for="sourceFilter">Source type</label>
              <select id="sourceFilter">
                <option value="">All</option>
                <option value="official">Official</option>
                <option value="wikidata">Wikidata</option>
                <option value="wikipedia">Wikipedia</option>
                <option value="none">None</option>
              </select>
            </div>
            <div class="filter-row">
              <label for="riskFilter">Risk filter</label>
              <select id="riskFilter">
                <option value="">All</option>
                <option value="risky">Risky rows</option>
                <option value="duplicate">Duplicate conflicts</option>
                <option value="contact">Contact mismatch</option>
                <option value="schema">Schema errors</option>
              </select>
            </div>
            <button id="clearFiltersBtn" type="button">Clear</button>
          </div>
        </aside>

        <article class="panel">
          <div class="panel-header">
            <div class="panel-title"><h2>Review Queue</h2><span id="queueCount"></span></div>
            <div class="toolbar">
              <select id="bulkStatus">
                <option value="Approved">Approve selected</option>
                <option value="Needs Review">Mark review</option>
                <option value="Risky">Mark risky</option>
              </select>
              <button id="bulkApplyBtn" type="button">Apply</button>
            </div>
          </div>
          <div class="panel-body">
            <div class="table-wrap">
              <table>
                <thead>
                  <tr>
                    <th style="width: 42px;"><input id="selectAllRows" type="checkbox" aria-label="Select all"></th>
                    <th>Institution</th>
                    <th>Location</th>
                    <th>Score</th>
                    <th>Status</th>
                    <th>Missing</th>
                    <th>Evidence</th>
                    <th>Review</th>
                    <th>Website</th>
                    <th>Action</th>
                  </tr>
                </thead>
                <tbody id="recordRows"></tbody>
              </table>
            </div>
          </div>
        </article>
      </section>

      <section data-view="export" hidden>
        <article class="panel">
          <div class="panel-header">
            <div class="panel-title"><h2>Export Readiness</h2><span>University_Import_Clean.csv</span></div>
            <div class="toolbar">
              <button id="validateExportBtn" type="button">Revalidate</button>
              <button id="downloadExportBtn" class="primary" type="button">Download</button>
            </div>
          </div>
          <div class="panel-body">
            <div class="export-box" id="exportMetrics"></div>
            <div class="table-wrap" style="margin-top: 14px;">
              <table>
                <thead>
                  <tr>
                    <th>Institution</th>
                    <th>Slug</th>
                    <th>Score</th>
                    <th>Status</th>
                    <th>Review</th>
                    <th>Blockers</th>
                  </tr>
                </thead>
                <tbody id="exportRows"></tbody>
              </table>
            </div>
          </div>
        </article>
      </section>
    </main>
  </div>

  <div class="drawer-backdrop" id="drawerBackdrop"></div>
  <aside class="drawer" id="recordDrawer" aria-label="Record editor">
    <div class="drawer-header">
      <div class="drawer-title">
        <h3 id="drawerTitle">Record Editor</h3>
        <div class="muted mono" id="drawerSlug"></div>
      </div>
      <button id="closeDrawerBtn" type="button">Close</button>
    </div>
    <div class="drawer-body">
