  };
  const sourceColors = {
    official: "#2f7d54",
    wikidata: "#6656a5",
    wikipedia: "#1f766f",
    source: "#a86f13",
    none: "#b63f3a",
  };
  const state = {
    payload: null,
    records: [],
    filtered: [],
    selected: new Set(),
    activeTab: "overview",
    editing: null,
    busy: false,
