  function initElements() {
    [
      "runMeta", "refreshBtn", "exportBtn", "kpis", "statusTotal", "statusChart", "statusLegend",
      "scoreBands", "sourceChart", "sourceLegend", "fieldCompletenessMeta", "heatmap", "outliers",
      "schemaIssues", "trustChart", "trustLegend", "riskFlags", "searchInput", "countryFilter",
      "statusFilter", "scoreFilter", "missingFilter", "sourceFilter", "riskFilter", "clearFiltersBtn",
      "queueCount", "bulkStatus", "bulkApplyBtn", "selectAllRows", "recordRows", "validateExportBtn",
      "downloadExportBtn", "exportMetrics", "exportRows", "drawerBackdrop", "recordDrawer",
      "drawerTitle", "drawerSlug", "closeDrawerBtn", "editorQuality", "editorEvidence", "recordForm",
      "reviewStatusInput", "reviewerInput", "reviewNoteInput", "editorFindings", "rerunChecksBtn",
