    const prodIndex = path.indexOf("/webhook/");
    if (prodIndex >= 0) return `${window.location.origin}${path.slice(0, prodIndex)}/webhook`;
    return `${window.location.origin}/webhook`;
  }

  function endpoints() {
    const base = getWebhookBase();
    return {
      api: `${base}/university-quality-api`,
      update: `${base}/university-record-update`,
      bulk: `${base}/university-bulk-status`,
      rerun: `${base}/university-rerun-checks`,
      exportCsv: `${base}/university-csv-download`,
    };
  }

  function escapeHtml(value) {
    return String(value ?? "")
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#039;");
  }

  function toast(message) {
    els.toast.textContent = message;
    els.toast.classList.add("open");
    window.clearTimeout(toast.timer);
    toast.timer = window.setTimeout(() => els.toast.classList.remove("open"), 2600);
  }

  function statusClass(status) {
    if (status === "Verified") return "verified";
    if (status === "Probable") return "probable";
    if (status === "Needs Review") return "review";
    if (status === "Risky") return "risky";
    return "neutral";
  }

  function setBusy(value) {
    state.busy = value;
    [els.refreshBtn, els.exportBtn, els.bulkApplyBtn, els.downloadExportBtn, els.saveRecordBtn, els.rerunChecksBtn]
      .filter(Boolean)
      .forEach((button) => { button.disabled = value; });
  }

  async function fetchJson(url, options) {
    const response = await fetch(url, {
      headers: { "Content-Type": "application/json", ...(options?.headers || {}) },
      ...options,
    });
    if (!response.ok) throw new Error(`${response.status} ${response.statusText}`);
    return response.json();
  }

  async function loadData() {
    setBusy(true);
    try {
      const payload = await fetchJson(endpoints().api);
      const records = Array.isArray(payload.records) ? payload.records : [];
      state.payload = payload;
      state.records = UniversityQuality.scoreBatch(records);
      state.payload = UniversityQuality.aggregate(state.records);
      state.payload.run = payload.run || payload.last_run || {};
      state.payload.updated_at = payload.generatedAt || new Date().toISOString();
      renderAll();
      toast("Dashboard refreshed");
    } catch (error) {
      state.payload = UniversityQuality.aggregate([]);
      state.records = [];
      renderAll();
      toast(`API unavailable: ${error.message}`);
    } finally {
      setBusy(false);
    }
  }

  function renderAll() {
    updateFilterOptions();
    applyFilters();
    renderKpis();
    renderOverview();
    renderQuality();
    renderTrust();
    renderReviewQueue();
    renderExport();
    const updated = state.payload?.updated_at ? new Date(state.payload.updated_at).toLocaleString() : "";
    els.runMeta.textContent = updated ? `Last update ${updated}` : "n8n dashboard";
  }

  function updateFilterOptions() {
    const locations = Array.from(new Set(state.records.map((record) => record.location).filter(Boolean))).sort();
    els.countryFilter.innerHTML = `<option value="">All</option>${locations.map((code) => `<option>${escapeHtml(code)}</option>`).join("")}`;
    els.missingFilter.innerHTML = `<option value="">All</option>${UniversityQuality.CSV_HEADERS.map((field) => `<option>${escapeHtml(field)}</option>`).join("")}`;
  }

  function kpi(label, value, meta) {
    return `<div class="kpi"><label>${escapeHtml(label)}</label><strong>${escapeHtml(value)}</strong><small>${escapeHtml(meta || "")}</small></div>`;
  }

  function renderKpis() {
    const s = state.payload?.summary || {};
    els.kpis.innerHTML = [
      kpi("Institutions", s.total || 0, "rows loaded"),
      kpi("Countries", s.countries || 0, "numeric ISO codes"),
      kpi("Verified", s.verified || 0, "score >= 85"),
      kpi("Probable", s.probable || 0, "score 70-84"),
      kpi("Needs Review", s.needs_review || 0, "manual queue"),
      kpi("Risky", s.risky || 0, "blocked risk"),
      kpi("Completeness", `${s.completeness_score || 0}%`, "field average"),
      kpi("Export Ready", s.export_ready || 0, `${s.export_blocked || 0} blocked`),
    ].join("");
  }

  function resizeCanvas(canvas) {
    const rect = canvas.getBoundingClientRect();
    const ratio = window.devicePixelRatio || 1;
    canvas.width = Math.max(1, Math.floor(rect.width * ratio));
    canvas.height = Math.max(1, Math.floor(canvas.getAttribute("height") * ratio));
    const ctx = canvas.getContext("2d");
    ctx.setTransform(ratio, 0, 0, ratio, 0, 0);
    return { ctx, width: rect.width, height: Number(canvas.getAttribute("height")) };
  }

  function renderLegend(el, labels, colors) {
    el.innerHTML = labels.map((label) => `<span class="legend-item"><i class="dot" style="background:${colors[label] || "#65736b"}"></i>${escapeHtml(label)}</span>`).join("");
  }

  function drawDonut(canvas, data, colors) {
    const { ctx, width, height } = resizeCanvas(canvas);
    ctx.clearRect(0, 0, width, height);
    const entries = Object.entries(data || {}).filter(([, value]) => Number(value) > 0);
    const total = entries.reduce((sum, [, value]) => sum + Number(value), 0);
    const cx = width / 2;
    const cy = height / 2;
    const radius = Math.min(width, height) / 2 - 18;
    if (!total) {
      ctx.fillStyle = "#65736b";
      ctx.font = "13px sans-serif";
      ctx.textAlign = "center";
      ctx.fillText("No data", cx, cy);
      return;
    }
    let start = -Math.PI / 2;
    entries.forEach(([label, value]) => {
      const angle = (Number(value) / total) * Math.PI * 2;
      ctx.beginPath();
      ctx.arc(cx, cy, radius, start, start + angle);
      ctx.arc(cx, cy, radius * 0.58, start + angle, start, true);
      ctx.closePath();
      ctx.fillStyle = colors[label] || "#65736b";
      ctx.fill();
      start += angle;
    });
    ctx.fillStyle = "#1d2520";
    ctx.font = "700 26px sans-serif";
    ctx.textAlign = "center";
    ctx.fillText(String(total), cx, cy - 2);
    ctx.fillStyle = "#65736b";
    ctx.font = "12px sans-serif";
    ctx.fillText("records", cx, cy + 18);
  }

  function drawBars(canvas, data, colors) {
    const { ctx, width, height } = resizeCanvas(canvas);
    ctx.clearRect(0, 0, width, height);
    const entries = Object.entries(data || {});
    const max = Math.max(1, ...entries.map(([, value]) => Number(value)));
    const rowH = Math.max(32, (height - 24) / Math.max(1, entries.length));
    ctx.font = "12px sans-serif";
    entries.forEach(([label, value], index) => {
      const y = 16 + index * rowH;
      const barW = Math.max(2, ((width - 132) * Number(value)) / max);
      ctx.fillStyle = "#65736b";
      ctx.textAlign = "left";
      ctx.fillText(label, 0, y + 12);
      ctx.fillStyle = "#e9eeeb";
      ctx.fillRect(112, y, width - 132, 14);
      ctx.fillStyle = colors[label] || "#1f766f";
      ctx.fillRect(112, y, barW, 14);
      ctx.fillStyle = "#1d2520";
      ctx.textAlign = "right";
      ctx.fillText(String(value), width - 2, y + 12);
    });
  }

  function renderBarList(el, data, color) {
    const entries = Object.entries(data || {});
    const max = Math.max(1, ...entries.map(([, value]) => Number(value)));
    el.innerHTML = entries.map(([label, value]) => `
      <div class="bar-row">
        <span>${escapeHtml(label)}</span>
        <div class="bar-track"><i class="bar-fill" style="width:${(Number(value) / max) * 100}%;background:${color || "#1f766f"}"></i></div>
        <strong>${escapeHtml(value)}</strong>
      </div>
    `).join("") || `<div class="empty">No data</div>`;
  }

  function renderOverview() {
    const charts = state.payload?.charts || {};
    els.statusTotal.textContent = `${state.payload?.summary?.total || 0} records`;
    drawDonut(els.statusChart, charts.status_counts || {}, statusColors);
    renderLegend(els.statusLegend, Object.keys(statusColors), statusColors);
    renderBarList(els.scoreBands, charts.score_bands || {}, "#6656a5");
    drawBars(els.sourceChart, charts.source_mix || {}, sourceColors);
    renderLegend(els.sourceLegend, Object.keys(sourceColors), sourceColors);
  }

  function heatColor(pct) {
    if (pct >= 90) return "#2f7d54";
    if (pct >= 70) return "#1f766f";
    if (pct >= 45) return "#a86f13";
    return "#b63f3a";
  }

  function renderQuality() {
    const fields = state.payload?.fieldCompleteness || {};
    const total = state.payload?.summary?.total || 0;
    els.fieldCompletenessMeta.textContent = `${total} records`;
    els.heatmap.innerHTML = Object.entries(fields).map(([field, item]) => `
      <div class="heat-cell">
        <strong>${escapeHtml(field)}</strong>
        <div class="heat-rail"><i style="width:${item.pct || 0}%;background:${heatColor(item.pct || 0)}"></i></div>
        <span>${item.pct || 0}% present, ${item.missing || 0} missing</span>
      </div>
    `).join("") || `<div class="empty">No fields</div>`;
    renderBarList(els.outliers, state.payload?.charts?.numeric_outliers || {}, "#a86f13");
    const issues = (state.payload?.findings || [])
      .filter((finding) => finding.rule_id.startsWith("csv.") || finding.rule_id.startsWith("outlier."))
      .slice(0, 60);
    renderIssues(els.schemaIssues, issues);
  }

  function renderTrust() {
    const truth = state.payload?.charts?.status_counts || {};
    drawBars(els.trustChart, truth, statusColors);
    renderLegend(els.trustLegend, Object.keys(statusColors), statusColors);
    const flags = (state.payload?.findings || [])
      .filter((finding) => finding.rule_id.includes("contact.") || finding.rule_id.includes("duplicate.") || finding.rule_id.includes("evidence."))
      .slice(0, 80);
    renderIssues(els.riskFlags, flags);
  }

  function renderIssues(el, issues) {
    if (!issues.length) {
      el.innerHTML = `<div class="empty">No issues</div>`;
      return;
    }
    el.innerHTML = issues.map((issue) => `
      <div class="issue ${escapeHtml(issue.severity || "minor")}">
        <strong>${escapeHtml(issue.severity || "")} · ${escapeHtml(issue.rule_id || "")}</strong>
        <span>${escapeHtml(issue.name || issue.field || "")}</span>
        <span>${escapeHtml(issue.message || "")}</span>
      </div>
    `).join("");
  }

  function applyFilters() {
    const text = els.searchInput?.value.trim().toLowerCase() || "";
    const country = els.countryFilter?.value || "";
    const status = els.statusFilter?.value || "";
    const scoreBand = els.scoreFilter?.value || "";
    const missing = els.missingFilter?.value || "";
    const source = els.sourceFilter?.value || "";
    const risk = els.riskFilter?.value || "";

    state.filtered = state.records.filter((record) => {
      if (text) {
        const haystack = `${record.name} ${record.slug} ${record.website} ${record.admissions_contact}`.toLowerCase();
        if (!haystack.includes(text)) return false;
      }
      if (country && record.location !== country) return false;
      if (status && record.quality_status !== status) return false;
      if (scoreBand) {
        const [min, max] = scoreBand.split("-").map(Number);
        if (record.quality_score < min || record.quality_score > max) return false;
      }
      if (missing && record[missing]) return false;
      if (source) {
        const types = new Set((record.evidence_links || []).map((entry) => entry.type));
        if (source === "none" && types.size) return false;
        if (source !== "none" && !types.has(source)) return false;
      }
      if (risk) {
        const flags = record.risky_flags || [];
        if (risk === "risky" && record.quality_status !== "Risky") return false;
        if (risk === "duplicate" && !flags.some((flag) => flag.includes("duplicate"))) return false;
        if (risk === "contact" && !flags.some((flag) => flag.includes("contact"))) return false;
        if (risk === "schema" && !record.critical_count) return false;
      }
      return true;
    });
  }

  function missingCount(record) {
    return UniversityQuality.CSV_HEADERS.filter((field) => !record[field] && !["id", "global_rank", "contact_person"].includes(field)).length;
  }

  function evidenceLabel(record) {
    const types = Array.from(new Set((record.evidence_links || []).map((entry) => entry.type)));
    return types.length ? types.join(", ") : "none";
  }

  function renderReviewQueue() {
    applyFilters();
    els.queueCount.textContent = `${state.filtered.length} shown`;
    if (!state.filtered.length) {
      els.recordRows.innerHTML = `<tr><td colspan="10"><div class="empty">No matching records</div></td></tr>`;
      return;
    }
    els.recordRows.innerHTML = state.filtered.map((record) => `
      <tr>
        <td><input type="checkbox" class="row-check" data-id="${escapeHtml(record.slug)}" ${state.selected.has(record.slug) ? "checked" : ""}></td>
        <td class="name-cell"><strong>${escapeHtml(record.name)}</strong><br><span class="muted mono">${escapeHtml(record.slug)}</span></td>
        <td>${escapeHtml(record.location)}</td>
        <td class="score">${escapeHtml(record.quality_score)}</td>
        <td><span class="pill ${statusClass(record.quality_status)}">${escapeHtml(record.quality_status)}</span></td>
        <td>${missingCount(record)}</td>
        <td>${escapeHtml(evidenceLabel(record))}</td>
        <td><span class="pill neutral">${escapeHtml(record.review_status || "Unreviewed")}</span></td>
        <td>${record.website ? `<a href="${escapeHtml(record.website)}" target="_blank" rel="noreferrer">open</a>` : `<span class="muted">blank</span>`}</td>
        <td><button type="button" class="edit-row" data-id="${escapeHtml(record.slug)}">Edit</button></td>
      </tr>
    `).join("");
  }

  function renderExport() {
    const check = UniversityQuality.validateExport(state.records);
    els.exportMetrics.innerHTML = [
      `<div class="metric"><label>Header order</label><strong>${check.headerOk ? "Valid" : "Invalid"}</strong></div>`,
      `<div class="metric"><label>Exportable rows</label><strong>${check.exportable.length}</strong></div>`,
      `<div class="metric"><label>Blocked rows</label><strong>${check.blocked.length}</strong></div>`,
    ].join("");
    const rows = [...check.exportable.map((record) => ({ ...record, blockers: "" })), ...check.blocked.map((record) => ({ ...record, blockers: `${record.critical_count} critical, ${record.review_status || "Unreviewed"}` }))];
    els.exportRows.innerHTML = rows.slice(0, 200).map((record) => `
      <tr>
        <td class="name-cell">${escapeHtml(record.name)}</td>
        <td class="mono">${escapeHtml(record.slug)}</td>
        <td class="score">${escapeHtml(record.quality_score)}</td>
        <td><span class="pill ${statusClass(record.quality_status)}">${escapeHtml(record.quality_status)}</span></td>
        <td>${escapeHtml(record.review_status || "Unreviewed")}</td>
        <td>${escapeHtml(record.blockers || "ready")}</td>
      </tr>
    `).join("") || `<tr><td colspan="6"><div class="empty">No rows</div></td></tr>`;
  }

  function switchTab(tab) {
    state.activeTab = tab;
    qsa(".tab").forEach((button) => button.classList.toggle("active", button.dataset.tab === tab));
    qsa("[data-view]").forEach((view) => { view.hidden = view.dataset.view !== tab; });
    window.requestAnimationFrame(() => {
      renderOverview();
      renderQuality();
      renderTrust();
    });
  }

  function openEditor(slug) {
    const record = state.records.find((item) => item.slug === slug);
    if (!record) return;
    state.editing = record;
    els.drawerTitle.textContent = record.name || "Record Editor";
    els.drawerSlug.textContent = record.slug || "";
    els.editorQuality.innerHTML = `
      <div class="export-box" style="grid-template-columns: repeat(2, minmax(0, 1fr));">
        <div class="metric"><label>Score</label><strong>${record.quality_score}</strong></div>
        <div class="metric"><label>Status</label><strong>${record.quality_status}</strong></div>
      </div>
      <div class="bar-list" style="margin-top: 12px;">
        ${Object.entries(record.score_components || {}).map(([label, value]) => `
          <div class="bar-row">
            <span>${escapeHtml(label)}</span>
            <div class="bar-track"><i class="bar-fill" style="width:${Number(value)}%;background:${heatColor(Number(value) * 5)}"></i></div>
            <strong>${escapeHtml(value)}</strong>
          </div>
        `).join("")}
      </div>
    `;
    els.editorEvidence.innerHTML = (record.evidence_links || []).map((entry) => `
      <a href="${escapeHtml(entry.url)}" target="_blank" rel="noreferrer">${escapeHtml(entry.type)}: ${escapeHtml(entry.url)}</a>
    `).join("") || `<span class="muted">No evidence links</span>`;
    els.recordForm.innerHTML = UniversityQuality.CSV_HEADERS.map((field) => {
      const full = ["description", "campus_student_life", "financials", "admissions_page_link"].includes(field) ? " full" : "";
      const value = record[field] ?? "";
      const input = ["description", "campus_student_life"].includes(field)
        ? `<textarea name="${field}">${escapeHtml(value)}</textarea>`
        : `<input name="${field}" value="${escapeHtml(value)}">`;
      return `<div class="form-field${full}"><label>${escapeHtml(field)}</label>${input}</div>`;
    }).join("");
    els.reviewStatusInput.value = record.review_status || "";
    els.reviewerInput.value = record.reviewer || "";
    els.reviewNoteInput.value = "";
    renderIssues(els.editorFindings, record.findings || []);
    els.drawerBackdrop.classList.add("open");
    els.recordDrawer.classList.add("open");
  }

  function closeEditor() {
    els.drawerBackdrop.classList.remove("open");
    els.recordDrawer.classList.remove("open");
    state.editing = null;
  }

  function collectEditorUpdates() {
    const data = {};
    new FormData(els.recordForm).forEach((value, key) => { data[key] = String(value).trim(); });
    data.review_status = els.reviewStatusInput.value;
    data.reviewer = els.reviewerInput.value.trim();
    return data;
  }

  async function saveRecord() {
    if (!state.editing) return;
    const updates = collectEditorUpdates();
    setBusy(true);
    try {
      await fetchJson(endpoints().update, {
        method: "POST",
        body: JSON.stringify({
          slug: state.editing.slug,
          updates,
          note: els.reviewNoteInput.value.trim(),
        }),
      });
      const index = state.records.findIndex((record) => record.slug === state.editing.slug);
      if (index >= 0) state.records[index] = UniversityQuality.scoreRecord({ ...state.records[index], ...updates });
      state.payload = UniversityQuality.aggregate(state.records);
      closeEditor();
      renderAll();
      toast("Record saved");
    } catch (error) {
      toast(`Save failed: ${error.message}`);
    } finally {
      setBusy(false);
    }
  }

  async function bulkApply() {
    const ids = Array.from(state.selected);
    if (!ids.length) {
      toast("No rows selected");
      return;
    }
    const status = els.bulkStatus.value;
    setBusy(true);
    try {
      await fetchJson(endpoints().bulk, {
        method: "POST",
        body: JSON.stringify({ slugs: ids, review_status: status, note: `Bulk ${status}` }),
      });
      state.records = state.records.map((record) => ids.includes(record.slug) ? UniversityQuality.scoreRecord({ ...record, review_status: status }) : record);
      state.selected.clear();
      state.payload = UniversityQuality.aggregate(state.records);
      renderAll();
      toast("Bulk action applied");
    } catch (error) {
      toast(`Bulk action failed: ${error.message}`);
    } finally {
      setBusy(false);
    }
  }

  function downloadCsv() {
    window.location.href = endpoints().exportCsv;
  }

  function bindEvents() {
    qsa(".tab").forEach((button) => button.addEventListener("click", () => switchTab(button.dataset.tab)));
    els.refreshBtn.addEventListener("click", loadData);
    els.exportBtn.addEventListener("click", downloadCsv);
    els.downloadExportBtn.addEventListener("click", downloadCsv);
    els.validateExportBtn.addEventListener("click", () => { renderExport(); toast("Export revalidated"); });
    [els.searchInput, els.countryFilter, els.statusFilter, els.scoreFilter, els.missingFilter, els.sourceFilter, els.riskFilter]
      .forEach((input) => input.addEventListener("input", renderReviewQueue));
    els.clearFiltersBtn.addEventListener("click", () => {
      [els.searchInput, els.countryFilter, els.statusFilter, els.scoreFilter, els.missingFilter, els.sourceFilter, els.riskFilter]
        .forEach((input) => { input.value = ""; });
      renderReviewQueue();
    });
    els.recordRows.addEventListener("change", (event) => {
      if (!event.target.classList.contains("row-check")) return;
      const id = event.target.dataset.id;
      if (event.target.checked) state.selected.add(id);
      else state.selected.delete(id);
    });
    els.recordRows.addEventListener("click", (event) => {
      const button = event.target.closest(".edit-row");
      if (button) openEditor(button.dataset.id);
    });
    els.selectAllRows.addEventListener("change", () => {
      if (els.selectAllRows.checked) state.filtered.forEach((record) => state.selected.add(record.slug));
      else state.filtered.forEach((record) => state.selected.delete(record.slug));
      renderReviewQueue();
    });
    els.bulkApplyBtn.addEventListener("click", bulkApply);
    els.closeDrawerBtn.addEventListener("click", closeEditor);
    els.drawerBackdrop.addEventListener("click", closeEditor);
    els.saveRecordBtn.addEventListener("click", saveRecord);
    els.rerunChecksBtn.addEventListener("click", () => {
      if (!state.editing) return;
      const updates = collectEditorUpdates();
      const rescored = UniversityQuality.scoreRecord({ ...state.editing, ...updates });
      state.editing = rescored;
      renderIssues(els.editorFindings, rescored.findings || []);
      toast("Checks rerun");
    });
    window.addEventListener("resize", () => {
      renderOverview();
      renderTrust();
    });
  }

  function start() {
    initElements();
    bindEvents();
    loadData();
  }

  return { start };
})();

document.addEventListener("DOMContentLoaded", app.start);
  </script>
</body>
</html>
";
return [{ json: { html } }];
